worker_processes auto;

events {
    worker_connections 1024;
}

http {
    include       mime.types;
    default_type  application/octet-stream;
    sendfile      on;
    keepalive_timeout 65;

    # ── Rate limit zones ─────────────────────────────────────────────────────
    limit_req_zone $binary_remote_addr zone=auth:10m   rate=30r/m;
    limit_req_zone $binary_remote_addr zone=submit:10m rate=10r/m;

    # ── Gzip ─────────────────────────────────────────────────────────────────
    gzip on;
    gzip_types text/css application/javascript application/json;

    # ── HTTPS server ──────────────────────────────────────────────────────────
    server {
        listen 443 ssl;
        http2 on;
        server_name _;

        # Cert paths match certbot Let's Encrypt layout so prod requires no changes.
        # For local dev, generate-self-signed.sh creates certs at these paths.
        ssl_certificate     /etc/letsencrypt/live/localhost/fullchain.pem;
        ssl_certificate_key /etc/letsencrypt/live/localhost/privkey.pem;

        ssl_protocols       TLSv1.2 TLSv1.3;
        ssl_ciphers         HIGH:!aNULL:!MD5;
        ssl_session_cache   shared:SSL:10m;
        ssl_session_timeout 10m;

        add_header Strict-Transport-Security "max-age=31536000; includeSubDomains" always;

        client_max_body_size 1m;

        # ── ACME challenge (Let's Encrypt renewal) ─────────────────────────
        location /.well-known/acme-challenge/ {
            root /var/www/acme;
        }

        # ── Auth endpoints — rate limited ──────────────────────────────────
        location /auth/ {
            limit_req zone=auth burst=10 nodelay;
            proxy_pass http://webide-app:8080;
            include /etc/nginx/proxy_pass.conf;
        }

        # ── Submission endpoint — rate limited ─────────────────────────────
        location /submissions {
            limit_req zone=submit burst=5 nodelay;
            proxy_pass http://webide-app:8080;
            include /etc/nginx/proxy_pass.conf;
        }

        # ── SignalR WebSocket upgrade ──────────────────────────────────────
        location /hubs/ {
            proxy_pass http://webide-app:8080;
            proxy_http_version 1.1;
            proxy_set_header Upgrade    $http_upgrade;
            proxy_set_header Connection "upgrade";
            proxy_read_timeout 86400;
            include /etc/nginx/proxy_pass.conf;
        }

        # ── Seq log UI — basic auth gated ─────────────────────────────────
        location /seq/ {
            auth_basic           "Seq";
            auth_basic_user_file /etc/nginx/htpasswd;
            proxy_pass           http://seq:80/;
            include /etc/nginx/proxy_pass.conf;
        }

        # ── Everything else ────────────────────────────────────────────────
        location / {
            proxy_pass http://webide-app:8080;
            include /etc/nginx/proxy_pass.conf;
        }
    }

    # ── HTTP redirect to HTTPS ────────────────────────────────────────────────
    server {
        listen 80;
        server_name _;

        # Allow ACME challenge through on port 80 for initial cert issuance
        location /.well-known/acme-challenge/ {
            root /var/www/acme;
        }

        location / {
            return 301 https://$host$request_uri;
        }
    }
}

